// src/GelirGider/GelirEkleme.js
import React, { useRef, useState, useMemo } from "react";
import * as XLSX from "xlsx";
import "./GelirEkleme.css";

export default function GelirEkleme() {
    const inputRef = useRef(null);
    const [isDragging, setIsDragging] = useState(false);
    const [file, setFile] = useState(null);
    const [error, setError] = useState("");

    // Sadece Excel
    const allowed = useMemo(() => [".xlsx", ".xls"], []);

    const openPicker = () => inputRef.current?.click();

    const onFilePicked = (e) => {
        const f = e.target.files?.[0];
        if (!f) return;
        validateAndSet(f);
    };

    const onDrop = (e) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(false);
        const f = e.dataTransfer.files?.[0];
        if (!f) return;
        validateAndSet(f);
    };

    const validateAndSet = (f) => {
        const ok = allowed.some((ext) => f.name.toLowerCase().endsWith(ext));
        if (!ok) {
            setError("Lütfen .xlsx veya .xls uzantılı bir dosya yükleyin.");
            setFile(null);
            return;
        }
        setError("");
        setFile(f);
    };

    const onDragOver = (e) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(true);
    };

    const onDragLeave = (e) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(false);
    };

    const reset = () => {
        setFile(null);
        setError("");
        if (inputRef.current) inputRef.current.value = "";
    };

    const formatSize = (bytes) => {
        if (bytes < 1024) return `${bytes} B`;
        if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
        return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
    };

    // ✅ Excel (.xlsx) şablon indir
    const downloadTemplate = () => {
        const data = [
            ["Tarih (YYYY-MM-DD)", "Kategori", "Tutar", "Açıklama"],       // başlıklar
            ["2025-01-15", "Satış", 12500.0, "Ocak online satış geliri"],  // örnek satır
        ];
        const ws = XLSX.utils.aoa_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Sablon");
        XLSX.writeFile(wb, "gelir_sablon.xlsx");
    };

    const upload = () => {
        if (!file) return;
        // Burada API'ye Excel'i göndereceksin (örnek):
        // const fd = new FormData();
        // fd.append("file", file);
        // await fetch("/api/gelir-yukle", { method: "POST", body: fd });

        alert(`Yüklendi: ${file.name}`);
        reset();
    };

    return (
        <div className="ge-page">
            {/* Üst bar */}
            <div className="ge-topbar">
                <div>
                    <h1>Gelir Ekleme</h1>
                    <p className="ge-sub">Excel ile toplu yükleme yap veya dosyayı sürükle-bırak.</p>
                </div>
                <div className="ge-top-actions">
                    <button className="btn ghost" onClick={downloadTemplate}>Şablonu İndir (.xlsx)</button>
                    <button className="btn" onClick={openPicker}>Dosya Seç</button>
                    <input
                        ref={inputRef}
                        type="file"
                        accept={[
                            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                            "application/vnd.ms-excel",
                            ".xlsx",
                            ".xls",
                        ].join(",")}
                        onChange={onFilePicked}
                        hidden
                    />
                </div>
            </div>

            {/* Drop zone */}
            <div
                className={`ge-drop ${isDragging ? "dragging" : ""}`}
                onDragOver={onDragOver}
                onDragLeave={onDragLeave}
                onDrop={onDrop}
                onClick={openPicker}
                role="button"
                tabIndex={0}
            >
                <div className="ge-drop-inner">
                    <div className="ge-icon">⬆️</div>
                    <div className="ge-title">Dosyanı buraya sürükle & bırak</div>
                    <div className="ge-muted">
                        veya <span className="ge-link">bilgisayardan seç</span> (.xlsx, .xls)
                    </div>
                </div>
            </div>

            {/* Seçilen dosya kartı */}
            {file && (
                <div className="ge-file">
                    <div className="ge-file-main">
                        <div className="ge-file-icon">📄</div>
                        <div>
                            <div className="ge-file-name">{file.name}</div>
                            <div className="ge-file-meta">{formatSize(file.size)}</div>
                        </div>
                    </div>
                    <button className="btn ghost danger" onClick={reset}>Kaldır</button>
                </div>
            )}

            {/* Hata */}
            {error && <div className="ge-error">{error}</div>}

            {/* Alt aksiyon barı */}
            <div className="ge-bottombar">
                <div className="ge-bottombar-left">
                    {file ? (
                        <span>Yüklemeye hazır: <strong>{file.name}</strong></span>
                    ) : (
                        <span>Henüz dosya seçilmedi</span>
                    )}
                </div>
                <div className="ge-bottombar-actions">
                    <button className="btn ghost" onClick={reset} disabled={!file}>Temizle</button>
                    <button className="btn" onClick={upload} disabled={!file}>Yükle</button>
                </div>
            </div>
        </div>
    );
}
